UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('knee-to-wall-ankle-rockers', 'Use wall target and simple cue: "knee kisses wall, heel stays down."', 'No sex-based default. Scale by ankle range, foot control, sport demand, tissue tolerance, body mass, landing history, and symptoms.'),
  ('half-kneeling-ankle-dorsiflexion-pulse', 'Use a wall target or cone in front of the knee.', 'No sex-based default. Scale by ankle range, foot control, sport demand, tissue tolerance, body mass, landing history, and symptoms.'),
  ('ankle-cars', 'Use "draw a circle with your big toe" cue.', 'No sex-based default. Scale by ankle range, foot control, sport demand, tissue tolerance, body mass, landing history, and symptoms.'),
  ('tibialis-raises', 'Seated toe lifts or wall version with feet closer.', 'No sex-based default. Scale by ankle range, foot control, sport demand, tissue tolerance, body mass, landing history, and symptoms.'),
  ('calf-raise-to-heel-drop', 'Double-leg only, hands on wall, 6–8 reps.', 'No sex-based default. Scale by ankle range, foot control, sport demand, tissue tolerance, body mass, landing history, and symptoms.'),
  ('toe-yoga', 'Make it a game: "big toe wave / little toe wave."', 'No sex-based default. Scale by ankle range, foot control, sport demand, tissue tolerance, body mass, landing history, and symptoms.'),
  ('short-foot-drill', 'Seated; coach uses "make a little arch bridge" cue.', 'No sex-based default. Scale by ankle range, foot control, sport demand, tissue tolerance, body mass, landing history, and symptoms.'),
  ('foot-tripod-weight-shifts', 'Use "three points of a triangle" cue.', 'No sex-based default. Scale by ankle range, foot control, sport demand, tissue tolerance, body mass, landing history, and symptoms.'),
  ('low-pogos', 'Start with marching or low ankle bounces holding a wall.', 'No sex-based default. Scale by ankle range, foot control, sport demand, tissue tolerance, body mass, landing history, and symptoms.'),
  ('jump-rope-easy-bounce', 'Use imaginary rope first; 10–20 seconds.', 'No sex-based default. Scale by ankle range, foot control, sport demand, tissue tolerance, body mass, landing history, and symptoms.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

